#include <stdio.h>
#include <string.h>

#define MAXLEN 505

int editDistance(const char *s, const char *t) {
    int m = strlen(s);
    int n = strlen(t);
    static int dp[MAXLEN][MAXLEN];
    for (int i = 0; i <= m; ++i) {
        for (int j = 0; j <= n; ++j) {
            if (i == 0) dp[i][j] = j;
            else if (j == 0) dp[i][j] = i;
            else if (s[i-1] == t[j-1]) dp[i][j] = dp[i-1][j-1];
            else {
                int del = dp[i-1][j];
                int ins = dp[i][j-1];
                int rep = dp[i-1][j-1];
                int mn = del < ins ? del : ins;
                mn = mn < rep ? mn : rep;
                dp[i][j] = 1 + mn;
            }
        }
    }
    return dp[m][n];
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    char src[MAXLEN];
    char tgt[MAXLEN];
    for (int tc = 0; tc < T; ++tc) {
        if (!fgets(src, MAXLEN, stdin)) src[0] = '\0';
        if (!fgets(tgt, MAXLEN, stdin)) tgt[0] = '\0';
        src[strcspn(src, "\n")] = '\0';
        tgt[strcspn(tgt, "\n")] = '\0';
        printf("%d\n", editDistance(src, tgt));
    }
    return 0;
}

