import sys

def edit_distance(s: str, t: str) -> int:
    m, n = len(s), len(t)
    dp = [[0] * (n + 1) for _ in range(m + 1)]
    for i in range(m + 1):
        dp[i][0] = i
    for j in range(n + 1):
        dp[0][j] = j
    for i in range(1, m + 1):
        si = s[i - 1]
        for j in range(1, n + 1):
            if si == t[j - 1]:
                dp[i][j] = dp[i - 1][j - 1]
            else:
                dp[i][j] = 1 + min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1])
    return dp[m][n]

data = sys.stdin.read().splitlines()
if not data:
    sys.exit()
T = int(data[0])
idx = 1
for _ in range(T):
    src = data[idx] if idx < len(data) else ''
    tgt = data[idx + 1] if idx + 1 < len(data) else ''
    idx += 2
    print(edit_distance(src, tgt))

